import React from 'react';
import { useNavigate } from 'react-router-dom';
import AuthForm from '../components/AuthForm';

const LandingPage = ({ onAuthSuccess }) => {
    const navigate = useNavigate();

    return (
        <div className="flex flex-col md:flex-row min-h-screen">
            
            {/* Left Section: AI Theme Banner (80%) */}
            <div className="md:w-3/5 p-12 bg-card shadow-2xl flex flex-col justify-center text-left">
                <h1 className="text-6xl font-extrabold text-ai-green mb-4 leading-tight">
                    AI-Powered Fitness <br/> & Prediction System
                </h1>
                <p className="text-xl text-gray-400 mb-8 max-w-lg">
                    Harnessing Deep Learning and Predictive Analytics to define your personalized path to optimal health.
                </p>
                <ul className="space-y-3 text-lg text-gray-300">
                    <li className="flex items-center"><span className="text-ai-green mr-3">✓</span> Image-Based Calorie Estimation</li>
                    <li className="flex items-center"><span className="text-ai-green mr-3">✓</span> Predictive Health Risk Analysis</li>
                    <li className="flex items-center"><span className="text-ai-green mr-3">✓</span> Dynamic Diet & Workout Recommendations</li>
                </ul>
            </div>

            {/* Right Section: Login/Register (20%) */}
            <div className="md:w-2/5 p-8 flex items-center justify-center bg-[#121212]">
                <div className="w-full max-w-sm">
                    <h2 className="text-3xl font-bold text-center text-white mb-6">Access Control</h2>
                    <AuthForm onAuthSuccess={onAuthSuccess} />
                    <p className="text-center text-sm text-gray-500 mt-6">
                        New user? Register above or log in with test@example.com / password123.
                    </p>
                </div>
            </div>
        </div>
    );
};

export default LandingPage;
